def on_form_load():
    import sys
    if hasattr(sys, '_shared_load_file'):
        try:
            with open(sys._shared_load_file, 'r') as f:
                txt_editor.caption = f.read()
            sys._shared_filename = sys._shared_load_file
            del sys._shared_load_file
        except Exception as e:
            msgbox(f'Error loading file:\n{e}')
    elif hasattr(sys, '_shared_editor_text'):
        txt_editor.caption = sys._shared_editor_text

def on_form_resize():
